import{_ as r,o as n,c as o,a2 as s}from"./chunks/framework.BWuWLRhz.js";const p="/images/debate2020/pinit_fg_en_rect_gray_20.png",u=JSON.parse('{"title":"The Trump-Biden Debate","description":"","frontmatter":{"title":"The Trump-Biden Debate","titleZh":"特朗普与拜登辩论","date":"2020-09-30T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2020/09/debate2020.html","slug":"debate2020"},"headers":[],"relativePath":"posts/debate2020.md","filePath":"posts/debate2020.md","lastUpdated":1782886257000}'),g={name:"posts/debate2020.md"};function e(a,t,i,l,h,m){return n(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="特朗普与拜登辩论-·-the-trump-biden-debate" tabindex="-1">特朗普与拜登辩论 · The Trump-Biden Debate <a class="header-anchor" href="#特朗普与拜登辩论-·-the-trump-biden-debate" aria-label="Permalink to &quot;特朗普与拜登辩论 · The Trump-Biden Debate&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2020/09/debate2020.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2020/09/debate2020.html</a> · 2020-09-30</p></blockquote><p>万一你错过了,这里是<a href="https://www.youtube.com/watch?v=5cathmZFeXs&amp;ab_channel=NBCNews" target="_blank" rel="noreferrer">第一场特朗普-拜登辩论</a>的文字记录:</p><p><strong>克里斯·华莱士 (Chris Wallace):</strong> 晚上好。我是克里斯·华莱士,欢迎大家来到——我预测——一场对我个人而言极其糟糕的体验。今晚有六个 15 分钟的环节,每个环节一个主题。每个环节开始时,两位候选人各有 2 分钟不被打断的发言时间。剩余时间为自由讨论。观众已同意不搞低俗行为。两个竞选团队都签字同意了这些规则,所以肯定不会出什么岔子。有请两位候选人登场。</p><p>[候选人入场]</p><p><strong>华莱士:</strong> 我们先从最高法院开始。特朗普总统,您提名艾米·科尼·巴雷特 (Amy Coney Barrett) 接替已故的鲁思·巴德·金斯伯格 (Ruth Bader Ginsburg) 出任大法官。您说宪法明确规定您有义务提名一位大法官人选。副总统拜登,您称这是滥用权力。首先,请两位分别说明各自的立场。</p><p><strong>特朗普:</strong> 艾米·科尼·巴雷特是完美的提名人选。保守派爱她。自由派爱她。克里斯·华莱士爱她。</p><p><strong>拜登:</strong> 艾米·巴雷特会废除《平价医疗法案 (Affordable Care Act)》。而且,现在新的规矩是必须等大选之后才能提名。</p><p><strong>特朗普:</strong> 我不知道你在说什么,因为我上次查的时候,总统任期是四年,不是三年。你想搞共产主义医疗。</p><p><strong>拜登:</strong> 我不想搞共产主义医疗。我想扩大奥巴马医保 (Obamacare)。</p><p><strong>特朗普:</strong> 你党想搞共产主义医疗,你怕他们。</p><p><strong>拜登:</strong> 我可能怕他们,但我<em>就是</em>现在的民主党,所以就算我以前怕他们、现在也怕他们,我也不怕了。他们现在得听我的。那新冠 (Covid) 呢?总统害死了 20 万人。罗伊诉韦德案 (Roe v. Wade)。</p><p><strong>特朗普:</strong> 你要是不禁中国,得害死 200 万人。不是罗伊诉韦德案。</p><p><strong>华莱士:</strong> 好,我们回到医保话题几分钟。总统先生,过去四年您一直承诺要废除并取代奥巴马医保,但这四年您从未提出——</p><p><strong>特朗普:</strong> 我提出了。</p><p><strong>华莱士:</strong> ——一个方案——</p><p><strong>特朗普:</strong> 我当然提出了。</p><p><strong>华莱士:</strong> ——来——</p><p><strong>特朗普:</strong> 我当然提出了。</p><p><strong>华莱士:</strong> ——取代——</p><p><strong>特朗普:</strong> 我取消了个人强制投保条款。</p><p><strong>华莱士:</strong> 奥巴——</p><p><strong>特朗普:</strong> 个人强制投保条款就是个笑话。</p><p><strong>华莱士:</strong> ——马医保。</p><p><strong>特朗普:</strong> 个人强制投保条款是奥巴马医保里最烂的部分。</p><p><strong>华莱士:</strong> 我是本场辩——</p><p><strong>特朗普:</strong> 个人强制投保条款烂透了。</p><p><strong>华莱士:</strong> 我是本场辩论的<strong>主持人</strong>,请以此对待我。您从未提出过取代奥巴马医保的方案。那么特朗普的医保方案到底是什么?</p><p><strong>特朗普:</strong> 我在降低药品价格。胰岛素便宜得跟水一样。</p><p><strong>华莱士:</strong> 嗯哼。乔,你呢?你为什么要终结私人保险?</p><p><strong>拜登:</strong> 我不想终结私人保险。</p><p><strong>特朗普:</strong> 你和 Bernie Sanders 就是朋友。</p><p><strong>拜登:</strong> 我不是。我想——</p><p><strong>特朗普:</strong> 你是一坨屎,Joe。</p><p><strong>拜登:</strong> 我想确保——</p><p><strong>特朗普:</strong> 一个可悲的小人物。</p><p><strong>Wallace:</strong> 别再欺负 Joe 了,总统先生。</p><p><strong>特朗普:</strong> 你可关心 Bernie Sanders 了。你喜欢共产主义医疗。反正我问过医生了,他们说奥巴马医保 (Obamacare) 是场灾难。</p><p><strong>拜登:</strong> 他没有计划。</p><p><strong>Wallace:</strong> 换个话题,Joe,你的一些同事在谈论废除阻挠议事 (filibuster) 和扩充最高法院。你的立场是什么?</p><p><strong>拜登:</strong> 我的立场是投票是好事。美国人应该投票。这很简单。你就去投票站,排队,然后进入投票间,给你想投的候选人把那个小开关拨下去。有时候不是开关。</p><p><strong>特朗普:</strong> 你要扩充最高法院吗,Joe?告诉我们你打算怎么扩充最高法院,Joe。激进左翼在拉你这个木偶的线,Joe。你和我都知道,Joe。</p><p><strong>拜登:</strong> 闭嘴吧,老兄。</p><p><strong>Wallace:</strong> 进展得真顺利。好,下一环节。新冠肺炎 (Covid-19)。美国已经有超过 700 万确诊病例,超过 20 万人死亡。问题是,为什么民众应该相信你比你的对手更能应对这场公共卫生危机?</p><p><strong>拜登:</strong> 每天 4 万人感染新冠。20 万人死亡。他没有计划。他 2 月份就知道了。他撒谎。他慌了。他还夸中国。他没有计划。他在打高尔夫。</p><p><strong>特朗普:</strong> 我救了很多人的命。这是中国的错。你当时想让中国人过来。Fauci 博士和所有民主党州长都说:&quot;特朗普总统干得非常出色。&quot;而且不止他们。所有其他人也都这么说。&quot;特朗普总统干得非常出色,&quot;他们都这么说。我干得非常出色。防护服、口罩、呼吸机,你都不知道呼吸机怎么造,疫苗已经到了,随便哪周就能有。你根本不可能干出我这样的工作,因为你就是个随便什么老头。你连猪流感都搞不定。猪流感就是一场灾难。</p><p><strong>拜登:</strong> 他慌了。人死了。还会有更多人死,除非他变聪明点——</p><p><strong>特朗普:</strong> 你刚才用了&quot;聪明&quot;这个词?你撒谎说你上过 Delaware 州立大学。你是 Delaware 州立大学最差的学生。你就是个蠢货 Joe。我知道。Chris Wallace 也知道,是不是 Chris。</p><p><strong>Wallace:</strong></p><p><strong>特朗普:</strong></p><p><strong>拜登:</strong></p><p><strong>Wallace:</strong> 总统先生,你越来越多地质疑口罩的有效性。你不支持戴口罩吗?</p><p><strong>特朗普:</strong> 口罩好极了。我口袋里就有一个口罩。需要的时候我就戴。口罩都说我干得非常出色。Joe 就算没必要也戴口罩。他离我 200 英尺远都戴。他睡觉的时候也戴。</p><p><strong>Wallace:</strong> 副总统先生,这是真的吗?</p><p><strong>拜登:</strong> 你想开门做生意,就得有个计划。</p><p><strong>Wallace:</strong> 先生,我问的是口罩。</p><p><strong>拜登:</strong> 哦口罩?当然,你得戴口罩。</p><p><strong>华莱士:</strong> 好,下一个环节。经济。特朗普先生,你先说。</p><p><strong>特朗普:</strong> 这是个大鸡巴经济。</p><p><strong>拜登:</strong> 不是。</p><p><strong>华莱士:</strong> 好吧那说说税收。总统先生,据说您一年只交 750 美元的税。我女儿认识一个 15 岁的女孩,她每周日在电影院卖糖果,她一年交的税都不止 750 美元。所以这是真的吗,总统先生?你 2016 年和 2017 年交了多少税?</p><p><strong>特朗普:</strong> 好几百万。</p><p><strong>华莱士:</strong> 好几百万,先生?</p><p><strong>特朗普:</strong> 好几百万好几十亿。我不交税,因为奥巴马政府说我不用交。</p><p><strong>华莱士:</strong> 乔,你的税收计划是什么?</p><p><strong>拜登:</strong> 我要重建这个经济。我要创造就业。我们要买美国货。买美国船。美国钢。美国建筑。我们把一个繁荣的经济交到他手里,他给搞砸了。</p><p><strong>华莱士:</strong> 但你真的把一个繁荣的经济交给他了吗?他真的搞砸了吗?</p><p><strong>拜登:</strong> 当然啦,随便吧。他老说什么交易的艺术。中国把偷窃的艺术玩得炉火纯青。</p><p><strong>特朗普:</strong> 中国给你儿子的肚皮抹黄油了。</p><p><strong>拜登:</strong> 中国没干那种事。</p><p><strong>特朗普:</strong> 然后呢,乔?你知道之后发生了什么吗?你儿子跑去莫斯科。你知道那儿发生了什么吗乔?莫斯科给你儿子的肚皮抹黄油了。</p><p><strong>拜登:</strong> 那里什么都没发生。</p><p><strong>特朗普:</strong> 就是发生了,乔。莫斯科市长的老婆。她把他肚皮抹得油光锃亮。</p><p><strong>拜登:</strong> 你想聊家庭吗特朗普?聊聊你的家庭啊。他们的油脂和他们的鞋。这不是家庭的问题。这是关于美国人民的。这是关于家庭的。</p><p><strong>特朗普:</strong> 那乌克兰呢?</p><p><strong>华莱士:</strong> 你猜怎么着?该进入下一个——</p><p><strong>特朗普:</strong> 乌克兰把他抹得一塌——</p><p><strong>华莱士:</strong> 总统先生。</p><p><strong>特朗普:</strong> 乌克兰把他抹得贼油。</p><p><strong>华莱士:</strong> <em>总统</em>先生。</p><p><strong>特朗普:</strong> 闭嘴克里斯。乌克兰怎么说乔?</p><p><strong>华莱士:</strong> 啊啊啊啊啊啊啊啊啊啊</p><p><strong>特朗普:</strong></p><p><strong>华莱士:</strong> 现在我要说点事,我要你好好听着,总统先生。我受够你了。再敢胡闹,我就罚你面壁思过。</p><p><strong>特朗普:</strong> 你知道还有什么——</p><p><strong>华莱士:</strong> 我就<em>直接罚你面壁</em>,总统先生。到时候你就后悔了。现在我要你别再当个坏孩子了,听清楚了吗?</p><p><strong>特朗普:</strong> 他呢?他也该面壁。</p><p><strong>华莱士:</strong> 坦白讲,总统先生,你是那个更坏的孩子。</p><p><strong>特朗普:</strong> 他也够坏的。</p><p><strong>华莱士:</strong> 下个环节,我们谈种族。选民为什么要信任你们来处理这个国家面临的种族问题?副总统先生,从你开始。</p><p><strong>拜登:</strong> 我完全支持种族。这关乎公平 (equity)。关乎平等 (equality)。关乎沉着 (equanimity)。平衡 (equilibrium)。春分 (equinox)。我们需要修复这个国家种族主义和脆弱性的系统性公平问题。而这位总统一点都没做。他想修复的是纳粹的系统性公平问题。</p><p><strong>特朗普:</strong> 黑人爱我。谁都知道黑人爱我。街上老有黑人跑过来跟我说他们爱我。亚伯拉罕·林肯 (Abraham Lincoln)、弗雷德里克·道格拉斯 (Frederick Douglass) 和我三个人为黑人做的事,比乔做梦都做不到。乔不肯说“执法”这两个字。你为什么不说,乔?你为什么这么像个提线木偶,乔?你就是激进左派的玩具。你就是个溜溜球。激进左派不让你说“执法”,因为他们像玩溜溜球一样耍你,乔。</p><p><strong>华莱士:</strong> 我想聊聊抗议的话题。在很多城市,事情演变成了暴力。比如波特兰 (Portland),简直是个不折不扣的疯人院。拜登先生,您有没有给波特兰市长或俄勒冈州州长打过电话,说一句“这他妈是怎么回事?”</p><p><strong>拜登:</strong> 我没有他们的电话。不然我早打了。你有他们号码吗,克里斯?有的话发给我。再说了,他们处理得挺好的。</p><p><strong>特朗普:</strong> 是吗乔?挺好的?他们真的在街上杀人,简直是场灾难,波特兰却没人管。</p><p><strong>华莱士:</strong> 总统先生,您喜欢还是不喜欢白人至上主义者?</p><p><strong>特朗普:</strong> 当然不喜欢。我不是不喜欢,也不是不不喜欢,也不是不不不喜欢任何人。</p><p><strong>华莱士:</strong></p><p><strong>特朗普:</strong></p><p><strong>华莱士:</strong> 总统先生,您对白人至上主义者有什么话要说?</p><p><strong>特朗普:</strong> 拿好你们的枪,但我没下命令之前先别开火。反正现在 99% 的暴力都是左派干的。</p><p><strong>拜登:</strong> 噢别扯了。反法西斯行动 (Antifa) 是一种理念,不是一个组织。我听说这词的意思是“反法西斯”,那这样的话,行啊,把我也算上。再说了,谁没在心情糟的日子往老太太身上泼过尿?Antifa 的人就跟你我一样。</p><p><strong>华莱士:</strong> 我在这儿真是遭罪。我特别难受,我想走了,我过得非常非常不爽。下一个环节,我们就聊聊“为什么应该是你而不是对手当总统”吧。</p><p><strong>特朗普:</strong> 从来没有一个领导人做得比我多。我说的可不只是美国总统。曼德拉 (Mandela)。匈奴王阿提拉 (Attila the Hun)。凯撒 (Caesar)。图坦卡蒙王 (King Tut)。他们谁都没我做得多。是我团结了这个国家。美国历史上第一次,分裂被我终结了。我是第一个 100% 支持率的总统。再说说法官。我任命了 300 个法官。法官多到我屁股都塞不下,克里斯。你知道为什么吗?因为奥巴马和疯子乔叔叔忘了填这些位子。谁会那样啊。没人会那样。你忘带钥匙,行,我也忘过钥匙,我是人,谁都会忘钥匙,我有时也会落下钥匙。但落下法官,那是灾难。</p><p><strong>拜登:</strong> 这个人让这个国家变得更弱、更病、更穷、更胖、更邋遢、更油腻。我当副总统的时候敢跟普京 (Putin) 正面硬刚,而特朗普只是普京的小狗狗。他的抱抱兔。他的毛绒绒宝贝儿。</p><p><strong>特朗普:</strong> 至少普京不是我的干爹,不像对你儿子那样。</p><p><strong>拜登:</strong> 好啊说到这个,滚你妈的。第二,你说军人都是废物——我儿子在伊拉克服过役,他不是废物,他是爱国者。</p><p><strong>特朗普:</strong> 哪个儿子?那个废物还是那个死了的?</p><p><strong>拜登:</strong></p><p><strong>华莱士:</strong></p><p><strong>特朗普:</strong> 死了的那个我不认识,但要我说,那个废物被军队踢出来了,因为他嗑可乐嗑得爽,被开除军籍,然后就开始了他著名的舔肚皮巡演。</p><p><strong>拜登:</strong> 他的肚皮是干的!</p><p><strong>华莱士:</strong> 哦我操。我们说说气候变化吧。总统先生,您对气候变化的科学怎么看,您打算怎么应对?</p><p><strong>特朗普:</strong> 我要干净的水和空气。至于加州的大火,森林地面上全是死树和落叶。</p><p><strong>华莱士:</strong> 好,可是您对气候变化的科学怎么看?</p><p><strong>特朗普:</strong> 我要干净的水和空气。我种了一亿亿棵树。我们得把加州森林里的叶子捡起来。每年我都会接到电话。加州又着火了。因为他们又没把那些该死的叶子捡起来。你知道在欧洲,人家会捡叶子的。</p><p><strong>华莱士:</strong> 乔?</p><p><strong>拜登:</strong> 我想淘汰化石燃料电厂,投资可再生能源。我想过渡到电动车,建造绿色建筑,创造几百万个新工作岗位。</p><p><strong>特朗普:</strong> 他说的是绿色新政。那个55千万亿美元的绿色新政。</p><p><strong>拜登:</strong> 绿色新政是一个能自我买单的计划。会非常棒的。</p><p><strong>华莱士:</strong> 您支持绿色新政吗?</p><p><strong>拜登:</strong> 当然不支持。我说的是拜登计划。谁提绿色新政了?</p><p><strong>华莱士:</strong> 谢天谢地,我极其糟糕的一晚终于到了最后一个环节。选举诚信。我们对这次选举的公正性应该有多大信心?</p><p><strong>拜登:</strong> 没有任何证据表明邮寄选票有问题。特朗普是想说服大家不要投票。听我说,美国人民。出门去投票。如果我得到足够多的票,这一切就结束了,那个坏人就伤害不了你们了。他说什么都不重要,只要我得到足够多的票,他就真的不再当权了,这多爽啊。</p><p><strong>华莱士:</strong> 总统先生?</p><p><strong>特朗普:</strong> 一只松鼠的屁股里,克里斯。前几天有人就是在那儿发现了一张选票。一只松鼠在费城的一个公园里拉出了一张选票,一个男的捡了起来,你猜怎么着?选票上写着特朗普。真是大惊喜。这就是邮寄选票的下场。它们最后都落到了荒山野岭河里林子里的垃圾桶里,然后那垃圾桶被卷进一个漩涡,咱俩都知道漩涡是怎么回事儿的克里斯,然后被冲到岸边,然后一只松鼠钻进去把选票吃了。半个国家的选票已经在漩涡里和松鼠肚子里被找到了,而且全都是投给我的票。邮寄选票就是一场骗局。</p><p><strong>华莱士:</strong> 我们唯一可以肯定的一件事就是,这次选举将是一场闹剧。您会接受这场闹剧的结果,并告诉您的支持者和平地接受结果吗?</p><p><strong>特朗普:</strong> 如果没有舞弊,就接受。</p><p><strong>华莱士 (Wallace)</strong>:有没有任何可以预见的结果——你输了但不说是舞弊?</p><p><strong>特朗普 (Trump)</strong>:没有。我已经讲过松鼠的事了。如果我输了,我们就得把这个国家给终结了。</p><p><strong>华莱士</strong>:拜登 (Biden) 呢?</p><p><strong>拜登</strong>:如果我输了,这个国家还能继续运转。</p><p><strong>华莱士</strong>:以上就是我职业生涯的一大污点——虽然这显然不是我的错。谢谢大家,晚安。</p><hr><p>如果你喜欢 Wait But Why,订阅我们的邮件列表吧——我保证不烦人**<a href="https://mailchi.mp/waitbutwhy/email-signup" target="_blank" rel="noreferrer">邮件列表</a>**——有新文章我们会通知你。</p><p>想支持 Wait But Why,请<a href="https://www.patreon.com/waitbutwhy" target="_blank" rel="noreferrer"><strong>访问我们的 Patreon 页面</strong></a>。</p><hr><p><strong>更多内容:</strong></p><p><a href="https://waitbutwhy.com/2016/10/second-presidential-debate.html" target="_blank" rel="noreferrer"><strong>特朗普-克林顿市政厅辩论</strong></a></p><p><strong><a href="https://waitbutwhy.com/2014/02/american-presidents-washington-lincoln.html" target="_blank" rel="noreferrer">前 16 位美国总统的完整故事</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer">为什么你应该停止在意别人的看法</a></strong></p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2020/09/debate2020.html&amp;description=The%20Trump-Biden%20Debate" target="_blank" rel="noreferrer"><img src="'+p+'" alt=""></a></p>',143)])])}const b=r(g,[["render",e]]);export{u as __pageData,b as default};
